  /// ```dart
  /// Widget build(BuildContext context) {
  /// return WidgetsApp(
  /// shortcuts: <ShortcutActivator, Intent>{
  /// ... WidgetsApp.defaultShortcuts,
  /// const SingleActivator(LogicalKeyboardKey.select): const ActivateIntent(),
  /// },
  /// color: const Color(0xFFFF0000),
